```js
const rateLimit = require('express-rate-limit');
const limiter = rateLimit({ windowMs: 15 * 60 * 1000, max: 100 }); // 100 req/15 min
app.use(limiter);
```

### 3. ❌ No Global Error Handler
Unhandled errors will leak stack traces (revealing internal paths, dependencies, etc.) or silently crash the server.

```js
// At the bottom, after all routes:
app.use((err, req, res, next) => {
  console.error(err.stack); // Log internally, don't expose
  res.status(500).json({ error: 'Internal server error' });
});
```

### 4. 🔍 No 404 Handler
Missing routes fall through silently — Express's default 404 response can reveal framework information.

```js
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});
```

### 5. ⚙️ Hardcoded Port
Hardcoding `3000` prevents flexible deployment and can expose the port in source control.

```js
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```

### 6. 🧹 No Body Parsing or Input Validation Middleware
If POST/PUT routes are added, there's no body parser or schema validation in place. Add this now as a baseline:

```js
app.use(express.json({ limit: '10kb' })); // Limit payload size to prevent large-body DoS
app.use(express.urlencoded({ extended: false, limit: '10kb' }));
```
For validation, use a library like **Joi** or **zod** on any routes that accept user input.

### 7. 🌐 No CORS Policy
By default, Express is permissive about cross-origin requests. If this is an API, explicitly define allowed origins:

```js
const cors = require('cors');
app.use(cors({ origin: process.env.ALLOWED_ORIGINS?.split(',') || [] }));
```

### 8. 📧 PII Exposure on `/users`
The `/users` endpoint returns `email` addresses. Even with hardcoded data today, this sets a bad pattern — sensitive fields should be explicitly excluded when constructing API responses.

---

## Revised `app.js`

```js
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');

const app = express();
const PORT = process.env.PORT || 3000;

// Security middleware
app.use(helmet());
app.use(cors({ origin: process.env.ALLOWED_ORIGINS?.split(',') || [] }));
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));
app.use(rateLimit({ windowMs: 15 * 60 * 1000, max: 100 }));

// Routes
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (req, res) => {
  const users = [
    { id: 1, name: 'Alice' }, // Email omitted from response
    { id: 2, name: 'Bob' },
  ];
  res.json(users);
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// Global error handler (must have 4 params for Express to treat as error middleware)
app.use((err, req, res, next) => {
  console.error(err.stack);
  res.status(err.status || 500).json({ error: 'Internal server error' });
});

app.listen(PORT, () => console.log(`Server running on port ${PORT}`));

module.exports = app;
```

---

## Summary of Changes

| Issue | Severity | Fix |
|---|---|---|
| No security headers | 🔴 High | Add `helmet` |
| No rate limiting | 🔴 High | Add `express-rate-limit` |
| No error handler | 🔴 High | Add 4-arg error middleware |
| PII in response | 🟠 Medium | Strip email from `/users` |
| No CORS config | 🟠 Medium | Add `cors` with explicit origin |
| No 404 handler | 🟡 Low | Add catch-all handler |
| Hardcoded port | 🟡 Low | Use `process.env.PORT` |
| No body size limit | 🟡 Low | Set `limit: '10kb'` on parsers |

**New dependencies to install:**
```bash
npm install helmet cors express-rate-limit
```

